    russian[optionsFilterPanelIdNameStart .. filterPanelIdStr]  = "LibFilters - Filter panel " .. filterPanelIdStr
    japanese[optionsFilterPanelIdNameStart .. filterPanelIdStr] = "LibFilters - Filter panel " .. filterPanelIdStr
end

